chart.config_raw:
const ctx = document.getElementById('breakEvenChart').getContext('2d');
new Chart(ctx, {
  type: 'bar',
  data: {
    labels: [
      'EXAONE 4.0\n32B ($2k)',
      'Qwen3-30B\n($2k)',
      'Magistral\nSmall ($2k)',
      'Llama-3.3\n70B ($15k)',
      'gpt-oss\n120B ($30k)',
      'GLM-4.5\nAir ($30k)',
      'Qwen3\n235B ($60k)',
      'GLM-4.5\n($90k)',
      'Kimi-K2\n($240k)'
    ],
    datasets: [{
      label: 'Break-even months vs GPT-5',
      data: [2.26, 2.5, 3.0, 17.8, 30.9, 34.0, 34.0, 51.5, 69.3],
      backgroundColor: [
        '#51cf66', '#51cf66', '#51cf66',
        '#4dabf7', '#4dabf7', '#4dabf7',
        '#f6ad55', '#f6ad55', '#ff6b6b'
      ],
      borderRadius: 6,
      borderSkipped: false
    }]
  },
  options: {
    animation: false,
    responsive: true,
    maintainAspectRatio: false,
    indexAxis: 'y',
    layout: {
      padding: { right: 20 }
    },
    plugins: {
      legend: { display: false },
      tooltip: {
        callbacks: {
          label: function(context) {
            return context.parsed.x + ' months';
          }
        }
      }
    },
    scales: {
      x: {
        title: {
          display: true,
          text: 'Months to break even',
          color: '#4a5568',
          font: { size: 13, weight: '600' }
        },
        grid: { color: '#e2e8f0' },
        ticks: {
          color: '#4a5568',
          callback: function(value) { return value + ' mo'; }
        }
      },
      y: {
        grid: { display: false },
        ticks: {
          color: '#4a5568',
          font: { size: 11.5 }
        }
      }
    }
  }
});
